        # Extract the 16 byte columns after the address; ignore ascii at the end
        # Common format: '00000000  xx xx xx xx xx xx xx xx  xx xx xx xx xx xx xx xx  |........|'
        m=re.match(r'^\s*[0-9a-fA-F]+\s+(.*)\s+\|', line)
